create or replace function public.security_qa_report() returns table (   check_name text,   status text,   severity text,   detail text ) language plpgsql security definer set search_path = public, pg_catalog as $$ declare   v_count integer;   v_detail text;   v_has_anon boolean := exists (select 1 from pg_roles where rolname = 'anon');   v_has_service_role boolean := exists (select 1 from pg_roles where rolname = 'service_role'); begin   return query   with required(table_name) as (     values       ('organizations'),       ('staff_users'),       ('members'),       ('pass_templates'),       ('member_passes'),       ('attendance_logs'),       ('member_notes'),       ('audit_logs'),       ('kiosk_attempt_logs')   )   select     ('rls enabled: ' || required.table_name)::text as check_name,     case when c.oid is not null and c.relrowsecurity then 'pass' else 'fail' end::text as status,     'blocker'::text as severity,     case       when c.oid is null then 'table is missing'       when not c.relrowsecurity then 'row level security is not enabled'       else 'ok'     end::text as detail   from required   left join pg_class c     on c.relname = required.table_name    and c.relnamespace = 'public'::regnamespace;   select count(*), coalesce(string_agg(c.relname || '.' || p.polname, ', ' order by c.relname, p.polname), '')   into v_count, v_detail   from pg_policy p   join pg_class c on c.oid = p.polrelid   where c.relnamespace = 'public'::regnamespace     and p.polname in (       'staff can manage members',       'staff can manage pass templates',       'staff can manage member passes',       'staff can manage attendance',       'staff can manage notes'     );   return query select     'no legacy broad staff manage policies'::text,     case when v_count = 0 then 'pass' else 'fail' end::text,     'blocker'::text,     case when v_count = 0 then 'ok' else v_detail end::text;   select count(*), coalesce(string_agg(c.relname || '.' || p.polname || ':' || p.polcmd, ', ' order by c.relname, p.polname), '')   into v_count, v_detail   from pg_policy p   join pg_class c on c.oid = p.polrelid   where c.relnamespace = 'public'::regnamespace     and c.relname in ('members','member_passes','attendance_logs','member_notes','audit_logs')     and p.polcmd in ('*','d');   return query select     'no delete or for-all RLS policies on operational tables'::text,     case when v_count = 0 then 'pass' else 'fail' end::text,     'high'::text,     case when v_count = 0 then 'ok' else v_detail end::text;   return query   with required(proname) as (     values       ('current_staff_organization_id'),       ('current_staff_role'),       ('current_staff_id')   )   select     ('helper function security definer: ' || required.proname)::text,     case when p.oid is not null and p.prosecdef then 'pass' else 'fail' end::text,     'blocker'::text,     case       when p.oid is null then 'function is missing'       when not p.prosecdef then 'function is not SECURITY DEFINER'       else 'ok'     end::text   from required   left join pg_proc p     on p.proname = required.proname    and p.pronamespace = 'public'::regnamespace;   return query   with required(proname) as (     values       ('current_staff_organization_id'),       ('current_staff_role'),       ('current_staff_id'),       ('check_in_member'),       ('cancel_attendance'),       ('adjust_remaining_sessions')   )   select     ('function search_path pinned: ' || required.proname)::text,     case when p.oid is not null and array_to_string(coalesce(p.proconfig, array[]::text[]), ' ') like '%search_path=public%' then 'pass' else 'fail' end::text,     'high'::text,     case       when p.oid is null then 'function is missing'       when array_to_string(coalesce(p.proconfig, array[]::text[]), ' ') not like '%search_path=public%' then 'search_path is not pinned to public'       else 'ok'     end::text   from required   left join pg_proc p     on p.proname = required.proname    and p.pronamespace = 'public'::regnamespace;   select count(*), coalesce(string_agg(p.proname, ', ' order by p.proname), '')   into v_count, v_detail   from pg_proc p   where p.pronamespace = 'public'::regnamespace     and p.proname in ('check_in_member','cancel_attendance','adjust_remaining_sessions')     and (       has_function_privilege('PUBLIC', p.oid, 'EXECUTE')       or (v_has_anon and has_function_privilege('anon', p.oid, 'EXECUTE'))     );   return query select     'critical RPC not executable by PUBLIC or anon'::text,     case when v_count = 0 then 'pass' else 'fail' end::text,     'blocker'::text,     case when v_count = 0 then 'ok' else v_detail end::text;   if v_has_service_role then     select count(*), coalesce(string_agg(p.proname, ', ' order by p.proname), '')     into v_count, v_detail     from pg_proc p     where p.pronamespace = 'public'::regnamespace       and p.proname in ('check_in_member','cancel_attendance','adjust_remaining_sessions')       and not has_function_privilege('service_role', p.oid, 'EXECUTE');     return query select       'critical RPC executable by service_role'::text,       case when v_count = 0 then 'pass' else 'fail' end::text,       'high'::text,       case when v_count = 0 then 'ok' else v_detail end::text;   else     return query select       'critical RPC executable by service_role'::text,       'warn'::text,       'medium'::text,       'service_role role was not found in this database'::text;   end if;   select count(*), coalesce(string_agg(p.proname, ', ' order by p.proname), '')   into v_count, v_detail   from pg_proc p   where p.pronamespace = 'public'::regnamespace     and p.proname = 'check_in_member'     and (       pg_get_functiondef(p.oid) not like '%p_source = ''kiosk''%'       or pg_get_functiondef(p.oid) not like '%service_role%'       or pg_get_functiondef(p.oid) not like '%?ㅼ삤?ㅽ겕 異쒖꽍? ?쒕쾭?먯꽌留?泥섎━?????덉뒿?덈떎%'     );   return query select     'kiosk check-in requires service_role path'::text,     case when v_count = 0 then 'pass' else 'fail' end::text,     'blocker'::text,     case when v_count = 0 then 'ok' else v_detail end::text;   return query   with required(table_name, policy_name) as (     values       ('members','staff can read members'),       ('members','ops staff can create members'),       ('members','ops staff can update members'),       ('member_passes','staff can read member passes'),       ('member_passes','ops staff can create member passes'),       ('member_passes','admins can update member passes'),       ('attendance_logs','staff can read attendance'),       ('attendance_logs','staff can insert no show attendance'),       ('audit_logs','admins can read audit'),       ('kiosk_attempt_logs','staff can read kiosk attempt logs'),       ('kiosk_attempt_logs','service can insert kiosk attempt logs')   )   select     ('required RLS policy exists: ' || required.table_name || '.' || required.policy_name)::text,     case when p.oid is not null then 'pass' else 'fail' end::text,     'high'::text,     case when p.oid is null then 'policy is missing' else 'ok' end::text   from required   left join pg_class c     on c.relname = required.table_name    and c.relnamespace = 'public'::regnamespace   left join pg_policy p     on p.polrelid = c.oid    and p.polname = required.policy_name;   select count(*), coalesce(string_agg(grantee || ':' || privilege_type, ', ' order by grantee, privilege_type), '')   into v_count, v_detail   from information_schema.role_table_grants   where table_schema = 'public'     and table_name = 'kiosk_attempt_logs'     and grantee in ('anon','authenticated')     and privilege_type in ('INSERT','UPDATE','DELETE');   return query select     'kiosk attempt logs write restricted'::text,     case when v_count = 0 then 'pass' else 'fail' end::text,     'high'::text,     case when v_count = 0 then 'ok' else v_detail end::text; end; $$;
